import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import axios from 'axios';
import Navbar from "./components/Navbar";

const cacheBusqueda = {};

function App() {
  // --- ESTADOS ---
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [authMode, setAuthMode] = useState('login'); 
  const [usuario, setUsuario] = useState('');
  const [password, setPassword] = useState('');
  const [email, setEmail] = useState(''); 
  const [telefono, setTelefono] = useState(''); 
  const [userRole, setUserRole] = useState('vendedor');
  const [nuevoRol, setNuevoRol] = useState('vendedor');
  const [fotoArchivo, setFotoArchivo] = useState(null); // Estado para la imagen

  const [view, setView] = useState('dashboard');
  const [filtroBajoStock, setFiltroBajoStock] = useState(false); 
  const [stats, setStats] = useState({ total_productos: 0, valor_inventario: 0, bajo_stock: 0 });
  const [productos, setProductos] = useState([]);
  const [busqueda, setBusqueda] = useState('');
  const [loading, setLoading] = useState(false);

  const [showForm, setShowForm] = useState(false);
  const [nuevoProd, setNuevoProd] = useState({ nombre: '', stock: '', precio_venta: '' });

  const [twoStep, setTwoStep] = useState(false); 
  const [otp, setOtp] = useState(''); 

  const abortControllerRef = useRef(null);

  // 1. CARGA DE DATOS
  const cargarDatos = useCallback(async () => {
    if (busqueda.length > 0) return; 
    setLoading(true);
    try {
      const [resStats, resProds] = await Promise.all([
        axios.get('http://localhost:5000/api/stats'),
        axios.get('http://localhost:5000/api/productos')
      ]);
      setStats(resStats.data);
      setProductos(resProds.data);
    } catch (error) { console.error(error); } 
    finally { setLoading(false); }
  }, [busqueda]);

  useEffect(() => {
    if (isLoggedIn) {
      cargarDatos();
      const interval = setInterval(cargarDatos, 30000);
      return () => clearInterval(interval);
    }
  }, [isLoggedIn, cargarDatos]);

  // 2. BUSQUEDA DINÁMICA
  const ejecutarBusqueda = useCallback(async (texto) => {
    if (texto.trim() === '') {
      cargarDatos();
      return;
    }
    if (cacheBusqueda[texto]) {
      setProductos(cacheBusqueda[texto]);
      return;
    }
    if (abortControllerRef.current) abortControllerRef.current.abort();
    abortControllerRef.current = new AbortController();
    try {
      const res = await axios.get(`http://localhost:5000/api/productos/buscar?q=${texto}`, { 
        signal: abortControllerRef.current.signal 
      });
      cacheBusqueda[texto] = res.data;
      setProductos(res.data);
    } catch (err) { if (err.name !== 'CanceledError') console.error(err); }
  }, [cargarDatos]);

  const optimizadaBusqueda = useMemo(() => {
    const debounce = (fn, delay) => {
      let timeout;
      return (...args) => {
        clearTimeout(timeout);
        timeout = setTimeout(() => fn(...args), delay);
      };
    };
    return debounce(ejecutarBusqueda, 300);
  }, [ejecutarBusqueda]);

  const handleBusquedaChange = (e) => {
    setBusqueda(e.target.value);
    optimizadaBusqueda(e.target.value);
  };

  // --- LÓGICA DE ACCESO ---
  const handleLogin = async () => {
    try {
      const res = await axios.post('http://localhost:5000/api/login', { usuario, clave: password });
      if (res.data.success) {
        setEmail(res.data.email);
        setTwoStep(true); 
      }
    } catch (e) { alert("Usuario o clave incorrectos"); }
  };

  const verificarOTP = async () => {
    try {
      const res = await axios.post('http://localhost:5000/api/verify-otp', { usuario, otp });
      if (res.data.success) {
        setUserRole(res.data.rol);
        setIsLoggedIn(true);
      } else { alert("Código incorrecto"); }
    } catch (e) { alert("Error"); }
  };

  const handleRegister = async () => {
    if (!usuario || !password || !email || !telefono) return alert("Faltan datos");
    try {
      await axios.post('http://localhost:5000/api/register', { email, usuario, telefono, clave: password, rol: nuevoRol });
      alert("¡Registro exitoso!");
      setAuthMode('login');
    } catch (e) { alert("Error al registrar"); }
  };

  // --- LÓGICA DE PRODUCTOS (CON FOTO) ---
  const guardarProducto = async () => {
    const formData = new FormData();
    formData.append('nombre', nuevoProd.nombre);
    formData.append('stock', Number(nuevoProd.stock));
    formData.append('precio_venta', Number(nuevoProd.precio_venta));
    if (fotoArchivo) {
      formData.append('imagen', fotoArchivo);
    }

    try {
      await axios.post('http://localhost:5000/api/productos', formData, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });
      setShowForm(false);
      cargarDatos();
      setNuevoProd({ nombre: '', stock: '', precio_venta: '' });
      setFotoArchivo(null);
      alert("¡Producto guardado!");
    } catch (e) { alert("Error al guardar"); }
  };

  const eliminar = async (id) => {
    if (window.confirm("¿Eliminar?")) {
      await axios.delete(`http://localhost:5000/api/productos/${id}`);
      cargarDatos();
    }
  };

  if (!isLoggedIn) {
    return (
      <div className="min-h-screen bg-[#bdc3c7] flex items-center justify-center p-4">
        <div className="bg-[#2d333b] p-10 rounded-[40px] shadow-2xl w-full max-w-sm border border-gray-700">
          {twoStep ? (
            <div className="text-center animate-in zoom-in duration-300">
              <i className="fas fa-lock text-[#00c984] text-5xl mb-6"></i>
              <h2 className="text-2xl font-bold text-white mb-2 uppercase">Verificación</h2>
              <input maxLength="6" placeholder="000000" className="w-full bg-[#444c56] text-white text-center text-5xl font-black py-4 rounded-3xl outline-none mb-8 tracking-[10px]" onChange={e => setOtp(e.target.value)} />
              <button className="w-full bg-[#00c984] text-[#1e293b] font-black py-4 rounded-3xl text-xl uppercase" onClick={verificarOTP}>Entrar</button>
            </div>
          ) : (
            <div className="space-y-4">
              <h2 className="text-3xl font-black text-white text-center uppercase tracking-tighter mb-6">Mi Tiendita Pro</h2>
              <input className="w-full bg-[#444c56] text-white px-6 py-4 rounded-2xl outline-none" placeholder="Usuario" onChange={e => setUsuario(e.target.value)} />
              {authMode === 'register' && (
                <>
                  <input className="w-full bg-[#444c56] text-white px-6 py-4 rounded-2xl outline-none" placeholder="Email" onChange={e => setEmail(e.target.value)} />
                  <input className="w-full bg-[#444c56] text-white px-6 py-4 rounded-2xl outline-none" placeholder="Teléfono" onChange={e => setTelefono(e.target.value)} />
                  <select className="w-full bg-[#444c56] text-white px-6 py-4 rounded-2xl outline-none" value={nuevoRol} onChange={e => setNuevoRol(e.target.value)}>
                    <option value="vendedor">Vendedor</option>
                    <option value="admin">Administrador</option>
                  </select>
                </>
              )}
              <input type="password" title="Contraseña" className="w-full bg-[#444c56] text-white px-6 py-4 rounded-2xl outline-none" placeholder="Contraseña" onChange={e => setPassword(e.target.value)} />
              <button className="w-full bg-[#00c984] text-[#1e293b] font-black py-4 rounded-2xl shadow-lg uppercase" onClick={authMode === 'login' ? handleLogin : handleRegister}>{authMode}</button>
              <p className="text-center text-[10px] text-gray-400 font-bold uppercase cursor-pointer" onClick={() => setAuthMode(authMode === 'login' ? 'register' : 'login')}>
                {authMode === 'login' ? 'Registro' : 'Login'}
              </p>
            </div>
          )}
        </div>
      </div>
    );
  }

  // FILTRO PARA EL BUSCADOR
  const productosFiltrados = productos.filter(p => 
    p.nombre.toLowerCase().includes(busqueda.toLowerCase())
  );

  return (
    <div className="min-h-screen bg-gray-50 text-slate-800">
      <Navbar setView={setView} userRole={userRole} logout={() => setIsLoggedIn(false)} busqueda={busqueda} handleBusquedaChange={handleBusquedaChange} />

      <main className="max-w-7xl mx-auto p-4 md:p-12">
        {busqueda.length > 0 ? (
          <div className="space-y-6 animate-in fade-in duration-300">
            <h2 className="text-3xl font-black uppercase tracking-tighter italic text-[#1e293b]">Resultados para: "{busqueda}"</h2>
            <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                {productosFiltrados.map(p => (
                  <div key={p.id} className="bg-white p-4 rounded-[30px] shadow-xl border border-gray-100 flex flex-col items-center text-center">
                    <img src={p.imagen ? `http://localhost:5000/uploads/${p.imagen}` : 'https://via.placeholder.com/150'} className="w-full h-40 object-cover rounded-2xl mb-4" alt="p" />
                    <h3 className="font-black text-slate-800 uppercase text-sm mb-1">{p.nombre}</h3>
                    <p className="text-green-600 font-black text-2xl mb-2">${p.precio_venta}</p>
                    <span className={`px-4 py-1 rounded-full text-[10px] font-black ${p.stock < 10 ? 'bg-red-100 text-red-600' : 'bg-gray-100 text-gray-400'}`}>Stock: {p.stock}</span>
                  </div>
                ))}
            </div>
          </div>
        ) : (
          <>
            {view === "dashboard" ? (
              <div className="space-y-10">
                <h2 className="text-3xl font-black uppercase italic tracking-tighter text-[#1e293b]">Resumen del Almacén</h2>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-8 text-center">
                  <div onClick={() => { setView('productos'); setFiltroBajoStock(false); }} className="bg-white p-10 border-2 rounded-[50px] shadow-xl cursor-pointer hover:scale-105 transition">
                    <p className="text-xs text-slate-400 font-black uppercase mb-2 tracking-widest italic">Stock Total</p>
                    <p className="text-5xl font-black text-[#1e293b]">{stats.total_productos}</p>
                  </div>
                  <div onClick={() => { setView('productos'); setFiltroBajoStock(true); }} className="bg-white p-10 border-2 rounded-[50px] shadow-xl cursor-pointer hover:scale-105 transition">
                    <p className="text-xs text-red-400 font-black uppercase mb-2 tracking-widest italic">Bajo Almacén</p>
                    <p className="text-5xl font-black text-red-500">{stats.bajo_stock}</p>
                  </div>
                  <div className="bg-white p-10 border-2 rounded-[50px] shadow-xl">
                    <p className="text-xs text-green-400 font-black uppercase mb-2 tracking-widest italic">Capital Invertido</p>
                    <p className="text-5xl font-black text-green-600">${stats.valor_inventario.toLocaleString()}</p>
                  </div>
                </div>
              </div>
            ) : (
              <div className="space-y-6">
                <div className="flex justify-between items-center">
                  <h2 className="text-3xl font-black uppercase tracking-tighter">
                    {filtroBajoStock ? "📦 Faltantes" : "📦 Todo el Almacén"}
                  </h2>
                  <button onClick={() => setShowForm(!showForm)} className="bg-[#1e293b] text-white px-8 py-3 rounded-2xl font-black text-xs uppercase shadow-lg">
                    {showForm ? 'Cerrar' : '+ Agregar Producto'}
                  </button>
                </div>
                {showForm && (
                  <div className="bg-white p-8 rounded-[40px] border-4 border-dashed grid grid-cols-1 md:grid-cols-5 gap-4 animate-in slide-in-from-top duration-300 shadow-inner">
                    <input className="p-4 bg-gray-50 rounded-2xl outline-none font-bold" placeholder="Nombre" value={nuevoProd.nombre} onChange={e => setNuevoProd({...nuevoProd, nombre: e.target.value})} />
                    <input className="p-4 bg-gray-50 rounded-2xl outline-none font-bold" placeholder="Stock" type="number" value={nuevoProd.stock} onChange={e => setNuevoProd({...nuevoProd, stock: e.target.value})} />
                    <input className="p-4 bg-gray-50 rounded-2xl outline-none font-bold" placeholder="Precio" type="number" value={nuevoProd.precio_venta} onChange={e => setNuevoProd({...nuevoProd, precio_venta: e.target.value})} />
                    {/* INPUT DE FOTO INTEGRADO */}
                    <div className="flex flex-col">
                        <p className="text-[10px] font-bold text-gray-400 ml-2 uppercase">Imagen</p>
                        <input type="file" className="text-xs mt-1" onChange={e => setFotoArchivo(e.target.files[0])} />
                    </div>
                    <button onClick={guardarProducto} className="bg-[#00c984] text-[#1e293b] font-black rounded-2xl py-4 uppercase shadow-lg">Guardar</button>
                  </div>
                )}
                <div className="bg-white border rounded-[40px] shadow-2xl overflow-hidden overflow-x-auto">
                  <table className="w-full text-left">
                    <thead className="bg-gray-100 text-[10px] font-black uppercase text-gray-400">
                      <tr><th className="p-6">Imagen</th><th className="p-6">Producto</th><th className="p-6 text-center">Stock</th><th className="p-6">Precio</th><th className="p-6 text-center">Borrar</th></tr>
                    </thead>
                    <tbody className="divide-y text-sm font-bold">
                      {productos.filter(p => filtroBajoStock ? p.stock < 10 : true).map(p => (
                        <tr key={p.id} className="hover:bg-slate-50 transition border-b border-gray-50">
                          <td className="p-6">
                             <img src={p.imagen ? `http://localhost:5000/uploads/${p.imagen}` : 'https://via.placeholder.com/50'} className="w-12 h-12 object-cover rounded-xl shadow-sm" alt="img" />
                          </td>
                          <td className="p-6 uppercase font-black text-[#1e293b]">{p.nombre}</td>
                          <td className="p-6 text-center">
                            <span className={`px-4 py-2 rounded-full text-[10px] font-black border ${p.stock < 10 ? 'bg-red-50 text-red-600 border-red-100' : 'bg-green-50 text-green-600 border-green-100'}`}>{p.stock} UNID.</span>
                          </td>
                          <td className="p-6 text-xl font-black text-slate-800">${p.precio_venta}</td>
                          <td className="p-6 text-center"><button onClick={() => eliminar(p.id)} className="text-red-300 hover:text-red-600"><i className="fas fa-trash-alt"></i></button></td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            )}
          </>
        )}
      </main>
    </div>
  );
}

export default App;
